@-moz-document domain("api.twitter.com"), domain("api.x.com") {
  :root {
    @media (prefers-color-scheme: light) {
      #catppuccin(@lightFlavor);
    }
    @media (prefers-color-scheme: dark) {
      #catppuccin(@darkFlavor);
    }
  }

  #catppuccin(@flavor) {
    #lib.palette();

    html {
      background: @mantle;
    }

    #header {
      color: @subtext0;
      background: @base;
      border-bottom-color: @surface1;

      .logo a {
        border-bottom-color: transparent;
      }

      #session {
        a {
          background: transparent;
          color: @subtext0;
        }

        h2 img {
          border-color: @surface1;
        }
      }
    }

    .footer {
      background: @mantle;
      border-top-color: @surface1;
    }

    .auth h2 {
      color: @subtext1;
    }

    .oauth #bd {
      border-color: @surface1;
    }

    .app-info h3 img {
      border-color: @base;
    }

    .permissions.allow strong {
      color: @green;
    }

    .button {
      background: @overlay0;
      color: @text;
      border-color: @surface1;

      &:hover {
        color: @text;
        border-color: @surface1;
        background: darken(@surface2, 10%);
      }
    }

    .button.selected,
    .follow-button .unfollow .button {
      background-color: @accent;
      color: if(@flavor = latte, #fff, @crust);
      border-color: darken(@accent, 10%);

      &:hover {
        background-color: darken(@accent, 10%);
      }

      .app-info,
      #bd h3 {
        color: @subtext0;
      }

      #ft {
        color: @overlay0;
      }
    }
  }
}

@-moz-document domain("twitter.com"), domain("x.com") {
  :root {
    @media (prefers-color-scheme: light) {
      #catppuccin(@lightFlavor);
    }
    @media (prefers-color-scheme: dark) {
      #catppuccin(@darkFlavor);
    }
  }

  #catppuccin(@flavor) {
    #lib.palette();

    #session a,
    #session input,
    #session button {
      background: @surface0;
      color: @subtext0;
    }

    #session .user-menu {
      a:focus,
      a:hover,
      button:focus,
      button:hover,
      input:focus,
      input:hover {
        color: if(@flavor = latte, #fff, @crust);
        background-color: @accent;
      }
    }

    .notice,
    .notice p,
    h2 {
      color: @subtext1;
    }

    .notice.error {
      background: fade(@red, 20%);
      border-color: fade(@red, 25%);
    }

    // report page? why isn't this themed
    .ResponsiveLayout--Night .PageContainer {
      background-color: @base;
    }

    .list-explanation {
      color: @subtext0;
    }

    .ResponsiveLayout--Night .list-btn {
      &:first-of-type {
        border-top-color: @mantle;
      }

      &:hover {
        background-color: @mantle;
      }
    }

    .submit-btn {
      background-color: @accent;
      color: if(@flavor = latte, #fff, @crust);
      border-color: darken(@accent, 10%);
    }

    .submit-btn:hover,
    .redirect-btn:hover {
      background-color: darken(@accent, 10%);
    }

    .block-btn {
      color: @maroon;
      border-color: @maroon;
    }

    .mute-btn,
    .unfollow-btn,
    .email-report-btn {
      color: @accent;
      border-color: @accent;
    }

    .list-btn {
      border-color: @surface1;

      &:first-of-type {
        border-top-color: @surface1;
      }

      &:hover {
        background-color: @surface0;
      }
    }

    // authorize page
    .js #session .user-menu {
      background-color: @surface0;
    }

    .dropdown-caret .caret-outer,
    .dropdown-caret .caret-inner {
      border-bottom-color: @surface0;
    }
  }
}

