}

.jw-overlay .jw-reset {
  border-radius: 4px !important;
}

.jw-slider-volume .jw-knob {
  border-radius: 50% !important;
}

.jw-controlbar, .jw-tooltip, .jw-text {
  font-family: var(--font-family);
  font-weight: 600;
  border-radius: 4px !important;
}

.jw-knob {
  height: 16px;
  width: 16px;
  background-color: var(--main-color);
}
}

